  "pattern": {
    "summary": "Compare of same-width values produced by width-changing casts can often be rewritten as a compare on the original wider values when nowrap/range facts make the discarded or introduced bits irrelevant. In particular, for icmp of trunc operands, if each operand is known to be exactly representable in the smaller type (e.g. via trunc nuw for unsigned preservation, trunc nsw for signed preservation, or a mix sufficient for the predicate), then the compare after truncation is equivalent to comparing the original values directly or to a simpler compare using the pre-cast operands.",
    "motivating_instance": {
      "source": "%at = trunc nuw i8 %a to i1
%bt = trunc nuw i8 %b to i1
%eq = icmp eq i1 %at, %bt",
      "optimized": "%eq = icmp eq i8 %a, %b",
      "reason": "trunc nuw to i1 implies each source is in {0,1}, so equality of truncated bits is identical to equality of original values."
    },
    "general_form": [
      "icmp <pred> TySmall (cast1 TyWide1 X to TySmall), (cast2 TyWide2 Y to TySmall)",
      "where cast1/cast2 are width-changing casts such as trunc, zext, sext, and nowrap/range information proves the compared TySmall values faithfully represent the original values for the relevant predicate",
      "rewrite to an equivalent icmp on X and Y, possibly after canonicalizing widths/casts"
    ],
    "important_preconditions": [
      "For trunc -> direct compare on originals, the source value on that side must be known to lie within the destination type's representable range in the way required by the predicate.",
      "trunc nuw X to iN means unsigned value of X fits in iN, so the upper discarded bits are known zero.",
      "trunc nsw X to iN means signed value of X fits in iN, so the discarded bits are sign-extension of the kept sign bit.",
      "Equality predicates often need only enough information to show the trunc is lossless on each side; relational predicates depend on signedness and cast kind.",
      "Mixed trunc/ext pairs are also candidates when extension recreates the original value class."
    ],
    "instcombine_fold_shape": {
      "match": "An icmp whose operands are trunc/trunc or trunc/ext (possibly symmetric), handled before other icmp canonicalization obscures the pattern.",
      "rewrite": "If foldICmpTruncWithTruncOrExt-style reasoning proves equivalence, rebuild the compare on the original operands or simpler casts with the corresponding predicate.",
